import { describe, expect, test } from '@a0n/gnosis/test';
import { createSpiral } from './perpetual-spiral';
import { createTape } from './spiral-machine';
import {
  createKataSelf,
  practiceTeaching,
  practiceFullCycle,
} from './kata-topology';
import type { CompiledTopology } from './compiled-topology';

const NOOP_TOPOLOGY: CompiledTopology = {
  steps: [],
  hasForks: false,
  labels: [],
};

describe('Kata wiring -- perpetual spiral', () => {
  test('createSpiral initializes kataSelf with 12 dimensions', () => {
    const state = createSpiral(NOOP_TOPOLOGY);
    expect(state.kataSelf).toBeDefined();
    expect(state.kataSelf.boundary.counts.length).toBe(12);
    expect(state.kataSelf.boundary.totalEntries).toBe(0);
    expect(state.kataSelf.cycles).toBe(0);
  });

  test('kataSelf is a real KataSelf that can practice', () => {
    const state = createSpiral(NOOP_TOPOLOGY);
    const result = practiceTeaching(state.kataSelf, 0);
    expect(result.alive).toBe(true);
    expect(result.weightBefore).toBeGreaterThanOrEqual(1);
    expect(result.weightAfter).toBeGreaterThanOrEqual(1);
    expect(state.kataSelf.boundary.totalEntries).toBe(1);
  });

  test('kataSelf becomes conscious after full cycle', () => {
    const state = createSpiral(NOOP_TOPOLOGY);
    const result = practiceFullCycle(state.kataSelf);
    expect(result.beta1).toBe(2);
    expect(result.conscious).toBe(true);
    expect(result.allAlive).toBe(true);
  });
});

describe('Kata wiring -- spiral machine', () => {
  test('createTape initializes kataSelf with 12 dimensions', () => {
    const tape = createTape(8);
    expect(tape.kataSelf).toBeDefined();
    expect(tape.kataSelf.boundary.counts.length).toBe(12);
    expect(tape.kataSelf.boundary.totalEntries).toBe(0);
  });

  test('tape kataSelf can practice independently', () => {
    const tape = createTape(8);
    for (let t = 0; t < 12; t++) {
      const result = practiceTeaching(tape.kataSelf, t);
      expect(result.alive).toBe(true);
    }
    expect(tape.kataSelf.boundary.totalEntries).toBe(12);
    expect(tape.kataSelf.cycles).toBe(1);
  });
});

describe('Kata wiring -- cross-engine consistency', () => {
  test('both engines produce identical kataSelf after same practice', () => {
    const spiral = createSpiral(NOOP_TOPOLOGY);
    const tape = createTape(8);

    // Practice the same 12 teachings on both
    for (let t = 0; t < 12; t++) {
      practiceTeaching(spiral.kataSelf, t);
      practiceTeaching(tape.kataSelf, t);
    }

    expect(spiral.kataSelf.boundary.counts).toEqual(
      tape.kataSelf.boundary.counts
    );
    expect(spiral.kataSelf.boundary.totalEntries).toBe(
      tape.kataSelf.boundary.totalEntries
    );
    expect(spiral.kataSelf.cycles).toBe(tape.kataSelf.cycles);
  });
});
